import type { ProjectBoardSection } from '@motivation/shared';
import stylesText from './project-scrumboard.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import { ProjectsService } from '../../../../services/projects.service.js';
import { renderMarkdown } from '../../../../utils/markdown.js';
import { createComponentLogger } from '../../../../utils/component-logger.js';

const template = document.createElement('template');
template.innerHTML = `
<p class="state" id="loading">Loading scrumboard…</p>
<pre class="state board-error" id="error" hidden></pre>
<div class="board" id="sections" hidden></div>
<template id="section-template">
    <section class="board-section">
        <h3 class="section-heading"></h3>
        <div class="section-body"></div>
    </section>
</template>
`;

/**
 * Read-only view of the live `docs/scrumboard.md`. The board is hand-edited prose (Now / Up Next /
 * area-grouped Backlog / Parked / Recently Done), so each section is rendered as its **verbatim
 * markdown** via the safe markdown walker — the in-app board is literally the board on disk.
 * Story creation (with a destination) lives in the stories list, not here.
 */
export class ProjectScrumboard extends HTMLElement {
    private shadowRootRef: ShadowRoot;
    private loadingEl!: HTMLElement;
    private errorEl!: HTMLElement;
    private sectionsEl!: HTMLElement;
    private sectionTemplateEl!: HTMLTemplateElement;
    private loadSequence = 0;
    private readonly log = createComponentLogger('project-scrumboard');

    static get observedAttributes(): string[] {
        return ['project-id'];
    }

    constructor() {
        super();
        this.shadowRootRef = this.attachShadow({ mode: 'open' });
        this.shadowRootRef.adoptedStyleSheets = [styles];
        this.shadowRootRef.appendChild(template.content.cloneNode(true));
    }

    connectedCallback(): void {
        this.loadingEl = this.shadowRootRef.getElementById('loading') as HTMLElement;
        this.errorEl = this.shadowRootRef.getElementById('error') as HTMLElement;
        this.sectionsEl = this.shadowRootRef.getElementById('sections') as HTMLElement;
        this.sectionTemplateEl = this.shadowRootRef.getElementById('section-template') as HTMLTemplateElement;
        void this.loadData();
    }

    attributeChangedCallback(): void {
        if (!this.isConnected || !this.loadingEl) return;
        void this.loadData();
    }

    private async loadData(): Promise<void> {
        const projectId = this.getAttribute('project-id');
        if (projectId !== 'motivation' || !this.loadingEl) return;

        const currentLoad = ++this.loadSequence;
        this.loadingEl.hidden = false;
        this.errorEl.hidden = true;
        this.sectionsEl.hidden = true;

        try {
            const dashboard = await ProjectsService.fetchMotivationDashboard();
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.renderSections(dashboard.scrumboard.sections);
        } catch (error) {
            this.log.error('Failed to load scrumboard', error);
            if (currentLoad !== this.loadSequence || !this.isConnected || !this.loadingEl) return;
            this.loadingEl.hidden = true;
            this.errorEl.hidden = false;
            this.errorEl.textContent = error instanceof Error ? error.stack ?? error.message : `Failed to load scrumboard: ${String(error)}`;
        }
    }

    private renderSections(sections: ProjectBoardSection[]): void {
        this.sectionsEl.replaceChildren(...sections.map((section) => this.buildSection(section)));
        this.loadingEl.hidden = true;
        this.errorEl.hidden = true;
        this.sectionsEl.hidden = false;
    }

    private buildSection(section: ProjectBoardSection): HTMLElement {
        const fragment = this.sectionTemplateEl.content.cloneNode(true) as DocumentFragment;
        const sectionEl = fragment.querySelector('.board-section') as HTMLElement;
        sectionEl.dataset.kind = section.kind;
        (fragment.querySelector('.section-heading') as HTMLElement).textContent = section.title;
        // baseHeadingLevel 2 maps the board's `### area` (depth 3) to <h4>, one below the
        // section's own <h3> — see renderMarkdown's `base + (depth - 1)` formula.
        (fragment.querySelector('.section-body') as HTMLElement)
            .appendChild(renderMarkdown(section.body, { baseHeadingLevel: 2 }));
        return sectionEl;
    }
}

if (!customElements.get('project-scrumboard')) {
    customElements.define('project-scrumboard', ProjectScrumboard);
}
